function initDots(){const c=document.getElementById("dotsContainer");c.innerHTML="";for(let i=0;i<TOTAL;i++){const d=document.createElement("button");d.className="dot"+(i===sc?" active":"");d.onclick=()=>goTo(i);c.appendChild(d);}}
function updateUI(){document.querySelectorAll(".nav-btn").forEach((b,i)=>{b.className="nav-btn"+(i===sc?" active":"");});document.querySelectorAll(".scene").forEach((s,i)=>{s.className="scene"+(i===sc?" active":"");});document.querySelectorAll(".dot").forEach((d,i)=>{d.className="dot"+(i===sc?" active":"");});document.getElementById("navLabel").textContent=(sc+1)+"/"+TOTAL+"  "+LABELS[sc].toUpperCase();const bb=document.getElementById("backBtn");bb.style.color=sc===0?"var(--ink5)":"var(--ink3)";const nb=document.getElementById("nextBtn");if(sc===TOTAL-1){nb.style.background="transparent";nb.style.color="var(--ink5)";nb.style.borderColor="var(--bd2)";}else{nb.style.background="var(--ink)";nb.style.color="var(--bg2)";nb.style.borderColor="var(--ink)";}startTimer();runSceneAnim();}
function startTimer(){const bar=document.getElementById("timerBar");bar.style.animation="none";bar.offsetHeight;if(DURS[sc]>0){bar.style.animation="timerW "+DURS[sc]+"ms linear forwards";if(timer)clearTimeout(timer);timer=setTimeout(advance,DURS[sc]);}else{bar.style.width="0%";}}
