function clearSceneTimers(){sceneTimers.forEach(t=>clearTimeout(t));sceneTimers=[];}
function makeRow(k,v,c,st,vis){return '<div style="display:flex;align-items:center;justify-content:space-between;padding:9px 0;border-bottom:1px solid var(--bd);opacity:'+(vis?1:0)+';transform:translateY('+(vis?0:5)+'px);transition:opacity .35s,transform .35s"><span style="font-family:var(--sans);font-size:12px;color:var(--ink3);font-weight:500">'+k+'</span><span style="font-family:var(--mono);font-size:11.5px;color:'+c+';font-weight:600;'+(st?"text-decoration:line-through":"")+'">'+v+'</span></div>';}
function animCounter(el,to,suf,dur){let start=null;const step=ts=>{if(!start)start=ts;const p=Math.min((ts-start)/dur,1);const v=Math.round((1-Math.pow(1-p,3))*to);el.textContent=v+suf;el.style.color=to>0?"var(--ink)":"var(--ink3)";if(p<1)requestAnimationFrame(step);};requestAnimationFrame(step);}
function runSceneAnim(){if(sc===1){buildPipeline();}if(sc===2){buildStealth();}if(sc===3){buildPerf();}if(sc===4){buildComps();}if(sc===5){buildPricing();}}
function buildPipeline(){const g=document.getElementById("pipeGrid");g.innerHTML="";PIPE.forEach((s,i)=>{const d=document.createElement("div");d.id="pipe"+i;d.style.cssText="background:var(--bg3);padding:18px 14px;position:relative;border-top:2px solid var(--bd);transition:all .4s";d.innerHTML='<div style="position:absolute;top:-5px;left:14px;width:8px;height:8px;border-radius:50%;background:var(--bg3);border:1px solid var(--bd2);transition:all .4s" id="pipeDot'+i+'"></div><div style="font-family:var(--mono);font-size:8px;letter-spacing:0.18em;color:var(--ink5);margin-bottom:8px;text-transform:uppercase;transition:color .3s" id="pipeLabel'+i+'">'+s.num+''+s.phase+'</div><div style="font-family:var(--disp);font-weight:800;font-size:13px;color:var(--ink4);margin-bottom:5px;transition:color .3s" id="pipeName'+i+'">'+s.name+'</div><div style="font-family:var(--sans);font-size:10px;color:var(--ink5);line-height:1.6;font-weight:500;transition:color .3s" id="pipeDesc'+i+'">'+s.desc+'</div>';g.appendChild(d);});const logs=document.getElementById("pipeLogs");logs.innerHTML='<span style="color:rgba(255,255,255,0.2)">Awaiting session<span style="animation:blink 1s infinite"></span></span>';document.getElementById("pipeProgress").style.width="0%";PIPE.forEach((_,i)=>{sceneTimers.push(setTimeout(()=>{lightPipe(i);},400+i*600));});sceneTimers.push(setTimeout(()=>{lightPipe(99);},400+PIPE.length*600+400));}
function lightPipe(idx){PIPE.forEach((_,i)=>{const on=idx===99||idx>=i;const green=i>=5;document.getElementById("pipe"+i).style.background=on?"var(--bg2)":"var(--bg3)";document.getElementById("pipe"+i).style.borderTopColor=on?(green?"var(--green)":"var(--ink)"):"var(--bd)";document.getElementById("pipeDot"+i).style.background=on?(green?"var(--green)":"var(--ink)"):"var(--bg3)";document.getElementById("pipeDot"+i).style.borderColor=on?(green?"var(--green)":"var(--ink)"):"var(--bd2)";document.getElementById("pipeLabel"+i).style.color=on?(green?"var(--green)":"var(--ink3)"):"var(--ink5)";document.getElementById("pipeName"+i).style.color=on?"var(--ink)":"var(--ink4)";document.getElementById("pipeDesc"+i).style.color=on?"var(--ink3)":"var(--ink5)";});const pct=idx===99?100:idx<0?0:((idx+1)/PIPE.length*100);document.getElementById("pipeProgress").style.width=pct+"%";if(idx>=0&&idx!==99&&idx<PIPE.length){const s=PIPE[idx];const logs=document.getElementById("pipeLogs");if(idx===0)logs.innerHTML="";const green=idx>=5;logs.innerHTML+='<div class="log-line"><span style="color:rgba(255,255,255,0.28);min-width:20px">'+s.num+'</span><span style="color:'+(green?"var(--greenhl)":"rgba(255,255,255,0.5)")+';min-width:58px;text-transform:uppercase;letter-spacing:0.08em">['+s.phase+']</span><span style="color:rgba(255,255,255,0.55)">'+s.name+'  '+s.desc.slice(0,55)+'</span></div>';}}
function buildStealth(){const sr=document.getElementById("stealthRows");const cr=document.getElementById("costRows");sr.innerHTML="";cr.innerHTML="";STEALTH.forEach((r,i)=>{sr.innerHTML+=makeRow(r.k,r.v,r.c,false,false);sceneTimers.push(setTimeout(()=>{sr.children[i].style.opacity=1;sr.children[i].style.transform="translateY(0)";},250+i*100));});COST.forEach((r,i)=>{cr.innerHTML+=makeRow(r.k,r.v,r.c,r.st,false);sceneTimers.push(setTimeout(()=>{cr.children[i].style.opacity=1;cr.children[i].style.transform="translateY(0)";},800+i*100));});}
function buildPerf(){animCounter(document.getElementById("stat0"),85,"%",1200);animCounter(document.getElementById("stat1"),75,"",1200);const pl=document.getElementById("perfLogs");pl.innerHTML='<span style="color:rgba(255,255,255,0.2)">Awaiting session<span style="animation:blink 1s infinite"></span></span>';let count=0;LOGS.forEach((l,i)=>{sceneTimers.push(setTimeout(()=>{if(i===0)pl.innerHTML="";count++;document.getElementById("perfCount").textContent=count+"/"+LOGS.length+" events";pl.innerHTML+='<div class="log-line"><span style="color:rgba(255,255,255,0.25);min-width:52px;flex-shrink:0">'+l.ts+'</span><span style="color:'+l.col+';flex-shrink:0;min-width:50px;text-transform:uppercase;letter-spacing:0.08em">['+l.tag+']</span><span style="color:rgba(255,255,255,0.55)">'+l.msg+'</span></div>';},400+i*520));});}
function buildComps(){const cr=document.getElementById("compRows");cr.innerHTML="";COMPS.forEach((c,i)=>{const us=c.us;const cols="1.8fr 1fr 1.2fr 1.2fr .8fr .8fr";const tick=v=>v===""?'<span style="color:var(--green);font-weight:700"></span>':v===""?'<span style="color:rgba(185,28,28,0.5)"></span>':'<span style="font-family:var(--mono);font-size:9.5px;color:'+(us?"var(--ink)":"var(--amber)")+';font-weight:600">'+v+'</span>';const row=document.createElement("div");row.style.cssText="display:grid;grid-template-columns:"+cols+";background:"+(us?"rgba(10,122,62,0.04)":(i%2===0?"var(--bg2)":"var(--bg3)"))+";border-bottom:1px solid var(--bd);opacity:0;transition:opacity .3s;border-left:"+(us?"3px solid var(--green)":"3px solid transparent");row.innerHTML='<div style="padding:10px 14px;display:flex;align-items:center;gap:7px;border-right:1px solid var(--bd)">'+(us?'<span style="width:5px;height:5px;border-radius:50%;background:var(--green);display:inline-block;flex-shrink:0"></span>':'')+'<span style="font-family:var(--sans);font-size:12.5px;color:'+(us?"var(--ink)":"var(--ink2)")+';font-weight:'+(us?700:500)+'">'+c.nm+'</span></div><div style="padding:10px 14px;text-align:center;border-right:1px solid var(--bd)"><span style="font-family:var(--mono);font-size:11px;color:'+(us?"var(--green)":"var(--ink3)")+';font-weight:'+(us?700:500)+'">'+c.pr+'</span></div><div style="padding:10px 14px;display:flex;align-items:center;justify-content:center;border-right:1px solid var(--bd)">'+tick(c.ai)+'</div><div style="padding:10px 14px;display:flex;align-items:center;justify-content:center;border-right:1px solid var(--bd)">'+tick(c.au)+'</div><div style="padding:10px 14px;display:flex;align-items:center;justify-content:center;border-right:1px solid var(--bd)">'+tick(c.st)+'</div><div style="padding:10px 14px;display:flex;align-items:center;justify-content:center">'+tick(c.ot)+'</div>';cr.appendChild(row);sceneTimers.push(setTimeout(()=>{row.style.opacity=1;},80+i*80));});}
function buildPricing(){const g=document.getElementById("pricingGrid");g.innerHTML="";const plans=[{nm:"Lifetime",pr:"$199",sub:"one-time",acc:"var(--ink)",note:"BEST VALUE",feats:["All 3 pipeline modes","Multi-account isolation","Lifetime updates (opt-in)","Community & docs"]},{nm:"Flex",pr:"$5",sub:"per month",acc:"var(--amber)",note:"BUDGET-FRIENDLY",feats:["Full feature parity","Cancel anytime","~40mo to own","No lock-in"]},{nm:"Pro+",pr:"$199",sub:"+ $29/mo maintenance",acc:"var(--green)",note:"BEST SUPPORT",feats:["Lifetime license","Priority bug fixes","Model upgrades","Dedicated channel"]}];let n=0;plans.forEach((p,i)=>{const d=document.createElement("div");d.style.cssText="background:var(--bg3);border:1px solid var(--bd2);border-top:2px solid "+p.acc+";padding:20px 18px;display:flex;flex-direction:column;opacity:0;transform:translateY(8px);transition:all .4s "+i*0.1+"s";d.innerHTML='<div style="font-family:var(--mono);font-size:9px;letter-spacing:0.16em;color:'+p.acc+';text-transform:uppercase;margin-bottom:10px;font-weight:700">'+p.note+'</div><div style="font-family:var(--disp);font-weight:800;font-size:13px;margin-bottom:7px">'+p.nm+'</div><div style="font-family:var(--disp);font-weight:800;font-size:clamp(30px,3vw,44px);color:'+p.acc+';line-height:1;margin-bottom:3px">'+p.pr+'</div><div style="font-family:var(--mono);font-size:9.5px;color:var(--ink4);letter-spacing:0.1em;margin-bottom:16px">'+p.sub+'</div><div style="height:1px;background:var(--bd2);margin-bottom:12px"></div><div style="display:flex;flex-direction:column;gap:7px">'+p.feats.map(f=>'<div style="display:flex;align-items:flex-start;gap:7px"><span style="color:'+p.acc+';font-weight:700;font-size:11px"></span><span style="font-family:var(--sans);font-size:11px;color:var(--ink3);line-height:1.5;font-weight:500">'+f+'</span></div>').join("")+'</div>';g.appendChild(d);sceneTimers.push(setTimeout(()=>{d.style.opacity=1;d.style.transform="translateY(0)";n++;},120+i*85));});
const rv=document.createElement("div");rv.style.cssText="background:var(--bg3);border:1px solid var(--bd2);padding:20px 18px;opacity:0;transition:all .4s .35s";const biz=[{l:"Break-even (10 clients)",v:"$1,990"},{l:"Revenue at 100 clients",v:"$19,900"},{l:"Flex MRR at 100 clients",v:"$500/mo"},{l:"Cost to serve / client",v:"~$5/mo"}];const sav=[{l:"vs Sprout Social (1yr)",v:"+$2,789"},{l:"vs Hypefury (1yr)",v:"+$389"},{l:"vs Tweet Hunter (1yr)",v:"+$389"},{l:"vs avg competitor (1yr)",v:"+$1,200"}];rv.innerHTML='<div style="font-family:var(--mono);font-size:9px;letter-spacing:0.16em;color:var(--green);text-transform:uppercase;margin-bottom:12px;font-weight:700">YOUR REVENUE</div>'+biz.map((m,i)=>'<div id="biz'+i+'" style="display:flex;align-items:center;justify-content:space-between;padding:6px 0;border-bottom:1px solid var(--bd);opacity:0;transition:opacity .3s"><span style="font-family:var(--sans);font-size:10.5px;color:var(--ink3);font-weight:500">'+m.l+'</span><span style="font-family:var(--mono);font-size:11px;color:var(--green);font-weight:700">'+m.v+'</span></div>').join("")+'<div style="font-family:var(--mono);font-size:9px;letter-spacing:0.16em;color:var(--ink3);text-transform:uppercase;margin:12px 0 8px;font-weight:700">CUSTOMER SAVINGS</div>'+sav.map((s,i)=>'<div id="sav'+i+'" style="display:flex;justify-content:space-between;align-items:center;padding:4px 0;opacity:0;transition:opacity .3s"><span style="font-family:var(--sans);font-size:10.5px;color:var(--ink3);font-weight:500">'+s.l+'</span><span style="font-family:var(--mono);font-size:11px;color:var(--ink);font-weight:700">'+s.v+'</span></div>').join("");g.appendChild(rv);sceneTimers.push(setTimeout(()=>{rv.style.opacity=1;},400));biz.forEach((_,i)=>{sceneTimers.push(setTimeout(()=>{document.getElementById("biz"+i).style.opacity=1;},500+i*85));});sav.forEach((_,i)=>{sceneTimers.push(setTimeout(()=>{document.getElementById("sav"+i).style.opacity=1;},900+i*65));});sceneTimers.push(setTimeout(()=>{document.getElementById("verdict").style.opacity=1;},1400));}
// Clock
clockTimer=setInterval(()=>{secs++;const mm=String(Math.floor(secs/60)).padStart(2,"0"),ss=String(secs%60).padStart(2,"0");document.getElementById("clock").textContent=mm+":"+ss;},1000);
// Keys
document.addEventListener("keydown",e=>{if(e.key==="ArrowRight"||e.key===" "){e.preventDefault();advance();}if(e.key==="ArrowLeft"){e.preventDefault();goBack();}});
// Init
initDots();updateUI();
</script></body></html>
